package com.seaquake6324.civitas.infrastructure.population;
import com.seaquake6324.civitas.application.*;import com.seaquake6324.civitas.domain.population.*;import com.seaquake6324.civitas.infrastructure.config.CivitasConfig;import com.seaquake6324.civitas.infrastructure.entity.CitizenEntity;import com.seaquake6324.civitas.infrastructure.entity.MaterializationLeaseManager;import com.seaquake6324.civitas.infrastructure.persistence.PopulationSavedData;import java.util.*;import net.minecraft.server.level.ServerLevel;
/** Main-thread permanent-death coordinator for explicit non-war causes. */
public final class CitizenPermanentDeathManager{private static final KillCitizenService KILL=new KillCitizenService();private static final RecordPartnerDeathService PARTNER=new RecordPartnerDeathService();private static final ReconcileOrphansAfterParentDeathService ORPHANS=new ReconcileOrphansAfterParentDeathService();private static long attempts,deaths,rejected,partnerFailures,orphansCreated,orphanFailures,orphanTruncations;private static final EnumMap<CitizenDeathCause,Long>counts=new EnumMap<>(CitizenDeathCause.class);private static String lastReason="not_run";
 public static boolean kill(CitizenEntity entity,ServerLevel level,CitizenDeathCause cause){attempts++;if(cause!=CitizenDeathCause.STARVATION&&cause!=CitizenDeathCause.DISEASE&&cause!=CitizenDeathCause.ACCIDENT){rejected++;lastReason="unsupported_cause";return false;}PopulationSavedData data=PopulationSavedData.get(level.getServer());UUID id=entity.citizenId().orElse(null);CitizenRecord current=id==null?null:data.citizen(id).orElse(null);if(data.readOnly()||current==null){rejected++;lastReason=data.readOnly()?"read_only":"missing_citizen";return false;}var result=KILL.kill(data,id,current.revision(),level.getGameTime(),cause);if(!result.success()){rejected++;lastReason="kill_"+result.failure().name().toLowerCase(Locale.ROOT);return false;}deaths++;counts.merge(cause,1L,Long::sum);var history=PARTNER.record(data,result.citizen());if(!history.success())partnerFailures++;var orphan=ORPHANS.reconcile(data,FamilyMemberRef.citizen(id),level.getGameTime(),PopulationAgingManager.rules(),CivitasConfig.PARENTAGE_PER_DEATH.get());orphansCreated+=orphan.orphaned();orphanFailures+=orphan.failures();if(orphan.truncated())orphanTruncations++;MaterializationLeaseManager.revoke(id);lastReason=cause.name().toLowerCase(Locale.ROOT);return true;}
 public static Metrics metrics(){return new Metrics(attempts,deaths,rejected,partnerFailures,orphansCreated,orphanFailures,orphanTruncations,Map.copyOf(counts),lastReason);}public record Metrics(long attempts,long deaths,long rejected,long partnerFailures,long orphansCreated,long orphanFailures,long orphanTruncations,Map<CitizenDeathCause,Long>counts,String lastReason){}private CitizenPermanentDeathManager(){}
}
